import{_ as l,o as i,c as a,ai as d}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Clawnet 重构","description":"","frontmatter":{"read_when":["规划节点 + 操作者客户端的统一网络协议","重新设计跨设备的审批、配对、TLS 和在线状态"],"summary":"Clawnet 重构：统一网络协议、角色、认证、审批、身份","title":"Clawnet 重构","x-i18n":{"generated_at":"2026-02-03T07:55:03Z","model":"claude-opus-4-5","provider":"pi","source_hash":"719b219c3b326479658fe6101c80d5273fc56eb3baf50be8535e0d1d2bb7987f","source_path":"refactor/clawnet.md","workflow":15}},"headers":[],"relativePath":"zh-CN/refactor/clawnet.md","filePath":"zh-CN/refactor/clawnet.md","lastUpdated":null}'),r={name:"zh-CN/refactor/clawnet.md"};function c(o,e,h,s,t,n){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="clawnet-重构-协议-认证统一" tabindex="-1"><a class="header-anchor" href="#clawnet-重构-协议-认证统一">#</a> Clawnet 重构（协议 + 认证统一）</h1><h2 id="嗨" tabindex="-1"><a class="header-anchor" href="#嗨">#</a> 嗨</h2><p>嗨 Peter — 方向很好；这将解锁更简单的用户体验 + 更强的安全性。</p><h2 id="目的" tabindex="-1"><a class="header-anchor" href="#目的">#</a> 目的</h2><p>单一、严谨的文档用于：</p><ul><li>当前状态：协议、流程、信任边界。</li><li>痛点：审批、多跳路由、UI 重复。</li><li>提议的新状态：一个协议、作用域角色、统一的认证/配对、TLS 固定。</li><li>身份模型：稳定 ID + 可爱的别名。</li><li>迁移计划、风险、开放问题。</li></ul><h2 id="目标-来自讨论" tabindex="-1"><a class="header-anchor" href="#目标-来自讨论">#</a> 目标（来自讨论）</h2><ul><li>所有客户端使用一个协议（mac 应用、CLI、iOS、Android、无头节点）。</li><li>每个网络参与者都经过认证 + 配对。</li><li>角色清晰：节点 vs 操作者。</li><li>中央审批路由到用户所在位置。</li><li>所有远程流量使用 TLS 加密 + 可选固定。</li><li>最小化代码重复。</li><li>单台机器应该只显示一次（无 UI/节点重复条目）。</li></ul><h2 id="非目标-明确" tabindex="-1"><a class="header-anchor" href="#非目标-明确">#</a> 非目标（明确）</h2><ul><li>移除能力分离（仍需要最小权限）。</li><li>不经作用域检查就暴露完整的 Gateway 网关控制平面。</li><li>使认证依赖于人类标签（别名仍然是非安全性的）。</li></ul><hr><h1 id="当前状态-现状" tabindex="-1"><a class="header-anchor" href="#当前状态-现状">#</a> 当前状态（现状）</h1><h2 id="两个协议" tabindex="-1"><a class="header-anchor" href="#两个协议">#</a> 两个协议</h2><h3 id="_1-gateway-网关-websocket-控制平面" tabindex="-1"><a class="header-anchor" href="#_1-gateway-网关-websocket-控制平面">#</a> 1) Gateway 网关 WebSocket（控制平面）</h3><ul><li>完整 API 表面：配置、渠道、模型、会话、智能体运行、日志、节点等。</li><li>默认绑定：loopback。通过 SSH/Tailscale 远程访问。</li><li>认证：通过 <code>connect</code> 的令牌/密码。</li><li>无 TLS 固定（依赖 loopback/隧道）。</li><li>代码： <ul><li><code>src/gateway/server/ws-connection/message-handler.ts</code></li><li><code>src/gateway/client.ts</code></li><li><code>docs/gateway/protocol.md</code></li></ul></li></ul><h3 id="_2-bridge-节点传输" tabindex="-1"><a class="header-anchor" href="#_2-bridge-节点传输">#</a> 2) Bridge（节点传输）</h3><ul><li>窄允许列表表面，节点身份 + 配对。</li><li>TCP 上的 JSONL；可选 TLS + 证书指纹固定。</li><li>TLS 在设备发现 TXT 中公布指纹。</li><li>代码： <ul><li><code>src/infra/bridge/server/connection.ts</code></li><li><code>src/gateway/server-bridge.ts</code></li><li><code>src/node-host/bridge-client.ts</code></li><li><code>docs/gateway/bridge-protocol.md</code></li></ul></li></ul><h2 id="当前的控制平面客户端" tabindex="-1"><a class="header-anchor" href="#当前的控制平面客户端">#</a> 当前的控制平面客户端</h2><ul><li>CLI → 通过 <code>callGateway</code>（<code>src/gateway/call.ts</code>）连接 Gateway 网关 WS。</li><li>macOS 应用 UI → Gateway 网关 WS（<code>GatewayConnection</code>）。</li><li>Web 控制 UI → Gateway 网关 WS。</li><li>ACP → Gateway 网关 WS。</li><li>浏览器控制使用自己的 HTTP 控制服务器。</li></ul><h2 id="当前的节点" tabindex="-1"><a class="header-anchor" href="#当前的节点">#</a> 当前的节点</h2><ul><li>macOS 应用在节点模式下连接到 Gateway 网关 bridge（<code>MacNodeBridgeSession</code>）。</li><li>iOS/Android 应用连接到 Gateway 网关 bridge。</li><li>配对 + 每节点令牌存储在 Gateway 网关上。</li></ul><h2 id="当前审批流程-exec" tabindex="-1"><a class="header-anchor" href="#当前审批流程-exec">#</a> 当前审批流程（exec）</h2><ul><li>智能体通过 Gateway 网关使用 <code>system.run</code>。</li><li>Gateway 网关通过 bridge 调用节点。</li><li>节点运行时决定审批。</li><li>UI 提示由 mac 应用显示（当节点 == mac 应用时）。</li><li>节点向 Gateway 网关返回 <code>invoke-res</code>。</li><li>多跳，UI 绑定到节点主机。</li></ul><h2 id="当前的在线状态-身份" tabindex="-1"><a class="header-anchor" href="#当前的在线状态-身份">#</a> 当前的在线状态 + 身份</h2><ul><li>来自 WS 客户端的 Gateway 网关在线状态条目。</li><li>来自 bridge 的节点在线状态条目。</li><li>mac 应用可能为同一台机器显示两个条目（UI + 节点）。</li><li>节点身份存储在配对存储中；UI 身份是分开的。</li></ul><hr><h1 id="问题-痛点" tabindex="-1"><a class="header-anchor" href="#问题-痛点">#</a> 问题/痛点</h1><ul><li>需要维护两个协议栈（WS + Bridge）。</li><li>远程节点上的审批：提示出现在节点主机上，而不是用户所在位置。</li><li>TLS 固定仅存在于 bridge；WS 依赖 SSH/Tailscale。</li><li>身份重复：同一台机器显示为多个实例。</li><li>角色模糊：UI + 节点 + CLI 能力没有明确分离。</li></ul><hr><h1 id="提议的新状态-clawnet" tabindex="-1"><a class="header-anchor" href="#提议的新状态-clawnet">#</a> 提议的新状态（Clawnet）</h1><h2 id="一个协议-两个角色" tabindex="-1"><a class="header-anchor" href="#一个协议-两个角色">#</a> 一个协议，两个角色</h2><p>带有角色 + 作用域的单一 WS 协议。</p><ul><li><strong>角色：node</strong>（能力宿主）</li><li><strong>角色：operator</strong>（控制平面）</li><li>操作者的可选<strong>作用域</strong>： <ul><li><code>operator.read</code>（状态 + 查看）</li><li><code>operator.write</code>（智能体运行、发送）</li><li><code>operator.admin</code>（配置、渠道、模型）</li></ul></li></ul><h3 id="角色行为" tabindex="-1"><a class="header-anchor" href="#角色行为">#</a> 角色行为</h3><p><strong>Node</strong></p><ul><li>可以注册能力（<code>caps</code>、<code>commands</code>、permissions）。</li><li>可以接收 <code>invoke</code> 命令（<code>system.run</code>、<code>camera.*</code>、<code>canvas.*</code>、<code>screen.record</code> 等）。</li><li>可以发送事件：<code>voice.transcript</code>、<code>agent.request</code>、<code>chat.subscribe</code>。</li><li>不能调用配置/模型/渠道/会话/智能体控制平面 API。</li></ul><p><strong>Operator</strong></p><ul><li>完整控制平面 API，受作用域限制。</li><li>接收所有审批。</li><li>不直接执行 OS 操作；路由到节点。</li></ul><h3 id="关键规则" tabindex="-1"><a class="header-anchor" href="#关键规则">#</a> 关键规则</h3><p>角色是按连接的，不是按设备。一个设备可以分别打开两个角色。</p><hr><h1 id="统一认证-配对" tabindex="-1"><a class="header-anchor" href="#统一认证-配对">#</a> 统一认证 + 配对</h1><h2 id="客户端身份" tabindex="-1"><a class="header-anchor" href="#客户端身份">#</a> 客户端身份</h2><p>每个客户端提供：</p><ul><li><code>deviceId</code>（稳定的，从设备密钥派生）。</li><li><code>displayName</code>（人类名称）。</li><li><code>role</code> + <code>scope</code> + <code>caps</code> + <code>commands</code>。</li></ul><h2 id="配对流程-统一" tabindex="-1"><a class="header-anchor" href="#配对流程-统一">#</a> 配对流程（统一）</h2><ul><li>客户端未认证连接。</li><li>Gateway 网关为该 <code>deviceId</code> 创建<strong>配对请求</strong>。</li><li>操作者收到提示；批准/拒绝。</li><li>Gateway 网关颁发绑定到以下内容的凭证： <ul><li>设备公钥</li><li>角色</li><li>作用域</li><li>能力/命令</li></ul></li><li>客户端持久化令牌，重新认证连接。</li></ul><h2 id="设备绑定认证-避免-bearer-令牌重放" tabindex="-1"><a class="header-anchor" href="#设备绑定认证-避免-bearer-令牌重放">#</a> 设备绑定认证（避免 bearer 令牌重放）</h2><p>首选：设备密钥对。</p><ul><li>设备一次性生成密钥对。</li><li><code>deviceId = fingerprint(publicKey)</code>。</li><li>Gateway 网关发送 nonce；设备签名；Gateway 网关验证。</li><li>令牌颁发给公钥（所有权证明），而不是字符串。</li></ul><p>替代方案：</p><ul><li>mTLS（客户端证书）：最强，运维复杂度更高。</li><li>短期 bearer 令牌仅作为临时阶段（早期轮换 + 撤销）。</li></ul><h2 id="静默批准-ssh-启发式" tabindex="-1"><a class="header-anchor" href="#静默批准-ssh-启发式">#</a> 静默批准（SSH 启发式）</h2><p>精确定义以避免薄弱环节。优选其一：</p><ul><li><strong>仅限本地</strong>：当客户端通过 loopback/Unix socket 连接时自动配对。</li><li><strong>通过 SSH 质询</strong>：Gateway 网关颁发 nonce；客户端通过获取它来证明 SSH。</li><li><strong>物理存在窗口</strong>：在 Gateway 网关主机 UI 上本地批准后，允许在短窗口内（例如 10 分钟）自动配对。</li></ul><p>始终记录 + 记录自动批准。</p><hr><h1 id="tls-无处不在-开发-生产" tabindex="-1"><a class="header-anchor" href="#tls-无处不在-开发-生产">#</a> TLS 无处不在（开发 + 生产）</h1><h2 id="复用现有-bridge-tls" tabindex="-1"><a class="header-anchor" href="#复用现有-bridge-tls">#</a> 复用现有 bridge TLS</h2><p>使用当前 TLS 运行时 + 指纹固定：</p><ul><li><code>src/infra/bridge/server/tls.ts</code></li><li><code>src/node-host/bridge-client.ts</code> 中的指纹验证逻辑</li></ul><h2 id="应用于-ws" tabindex="-1"><a class="header-anchor" href="#应用于-ws">#</a> 应用于 WS</h2><ul><li>WS 服务器使用相同的证书/密钥 + 指纹支持 TLS。</li><li>WS 客户端可以固定指纹（可选）。</li><li>设备发现为所有端点公布 TLS + 指纹。 <ul><li>设备发现仅是定位器提示；永远不是信任锚。</li></ul></li></ul><h2 id="为什么" tabindex="-1"><a class="header-anchor" href="#为什么">#</a> 为什么</h2><ul><li>减少对 SSH/Tailscale 的机密性依赖。</li><li>默认情况下使远程移动连接安全。</li></ul><hr><h1 id="审批重新设计-集中化" tabindex="-1"><a class="header-anchor" href="#审批重新设计-集中化">#</a> 审批重新设计（集中化）</h1><h2 id="当前" tabindex="-1"><a class="header-anchor" href="#当前">#</a> 当前</h2><p>审批发生在节点主机上（mac 应用节点运行时）。提示出现在节点运行的地方。</p><h2 id="提议" tabindex="-1"><a class="header-anchor" href="#提议">#</a> 提议</h2><p>审批是 <strong>Gateway 网关托管的</strong>，UI 传递给操作者客户端。</p><h3 id="新流程" tabindex="-1"><a class="header-anchor" href="#新流程">#</a> 新流程</h3><ol><li>Gateway 网关接收 <code>system.run</code> 意图（智能体）。</li><li>Gateway 网关创建审批记录：<code>approval.requested</code>。</li><li>操作者 UI 显示提示。</li><li>审批决定发送到 Gateway 网关：<code>approval.resolve</code>。</li><li>如果批准，Gateway 网关调用节点命令。</li><li>节点执行，返回 <code>invoke-res</code>。</li></ol><h3 id="审批语义-加固" tabindex="-1"><a class="header-anchor" href="#审批语义-加固">#</a> 审批语义（加固）</h3><ul><li>广播到所有操作者；只有活跃的 UI 显示模态框（其他显示 toast）。</li><li>先解决者获胜；Gateway 网关拒绝后续解决为已结算。</li><li>默认超时：N 秒后拒绝（例如 60 秒），记录原因。</li><li>解决需要 <code>operator.approvals</code> 作用域。</li></ul><h2 id="好处" tabindex="-1"><a class="header-anchor" href="#好处">#</a> 好处</h2><ul><li>提示出现在用户所在位置（mac/手机）。</li><li>远程节点的一致审批。</li><li>节点运行时保持无头；无 UI 依赖。</li></ul><hr><h1 id="角色清晰示例" tabindex="-1"><a class="header-anchor" href="#角色清晰示例">#</a> 角色清晰示例</h1><h2 id="iphone-应用" tabindex="-1"><a class="header-anchor" href="#iphone-应用">#</a> iPhone 应用</h2><ul><li><strong>Node 角色</strong>用于：麦克风、相机、语音聊天、位置、一键通话。</li><li>可选的 <strong>operator.read</strong> 用于状态和聊天视图。</li><li>可选的 <strong>operator.write/admin</strong> 仅在明确启用时。</li></ul><h2 id="macos-应用" tabindex="-1"><a class="header-anchor" href="#macos-应用">#</a> macOS 应用</h2><ul><li>默认是 Operator 角色（控制 UI）。</li><li>启用&quot;Mac 节点&quot;时是 Node 角色（system.run、屏幕、相机）。</li><li>两个连接使用相同的 deviceId → 合并的 UI 条目。</li></ul><h2 id="cli" tabindex="-1"><a class="header-anchor" href="#cli">#</a> CLI</h2><ul><li>始终是 Operator 角色。</li><li>作用域按子命令派生： <ul><li><code>status</code>、<code>logs</code> → read</li><li><code>agent</code>、<code>message</code> → write</li><li><code>config</code>、<code>channels</code> → admin</li><li>审批 + 配对 → <code>operator.approvals</code> / <code>operator.pairing</code></li></ul></li></ul><hr><h1 id="身份-别名" tabindex="-1"><a class="header-anchor" href="#身份-别名">#</a> 身份 + 别名</h1><h2 id="稳定-id" tabindex="-1"><a class="header-anchor" href="#稳定-id">#</a> 稳定 ID</h2><p>认证必需；永不改变。 首选：</p><ul><li>密钥对指纹（公钥哈希）。</li></ul><h2 id="可爱别名-龙虾主题" tabindex="-1"><a class="header-anchor" href="#可爱别名-龙虾主题">#</a> 可爱别名（龙虾主题）</h2><p>仅人类标签。</p><ul><li>示例：<code>scarlet-claw</code>、<code>saltwave</code>、<code>mantis-pinch</code>。</li><li>存储在 Gateway 网关注册表中，可编辑。</li><li>冲突处理：<code>-2</code>、<code>-3</code>。</li></ul><h2 id="ui-分组" tabindex="-1"><a class="header-anchor" href="#ui-分组">#</a> UI 分组</h2><p>跨角色的相同 <code>deviceId</code> → 单个&quot;实例&quot;行：</p><ul><li>徽章：<code>operator</code>、<code>node</code>。</li><li>显示能力 + 最后在线。</li></ul><hr><h1 id="迁移策略" tabindex="-1"><a class="header-anchor" href="#迁移策略">#</a> 迁移策略</h1><h2 id="阶段-0-记录-对齐" tabindex="-1"><a class="header-anchor" href="#阶段-0-记录-对齐">#</a> 阶段 0：记录 + 对齐</h2><ul><li>发布此文档。</li><li>盘点所有协议调用 + 审批流程。</li></ul><h2 id="阶段-1-向-ws-添加角色-作用域" tabindex="-1"><a class="header-anchor" href="#阶段-1-向-ws-添加角色-作用域">#</a> 阶段 1：向 WS 添加角色/作用域</h2><ul><li>用 <code>role</code>、<code>scope</code>、<code>deviceId</code> 扩展 <code>connect</code> 参数。</li><li>为 node 角色添加允许列表限制。</li></ul><h2 id="阶段-2-bridge-兼容性" tabindex="-1"><a class="header-anchor" href="#阶段-2-bridge-兼容性">#</a> 阶段 2：Bridge 兼容性</h2><ul><li>保持 bridge 运行。</li><li>并行添加 WS node 支持。</li><li>通过配置标志限制功能。</li></ul><h2 id="阶段-3-中央审批" tabindex="-1"><a class="header-anchor" href="#阶段-3-中央审批">#</a> 阶段 3：中央审批</h2><ul><li>在 WS 中添加审批请求 + 解决事件。</li><li>更新 mac 应用 UI 以提示 + 响应。</li><li>节点运行时停止提示 UI。</li></ul><h2 id="阶段-4-tls-统一" tabindex="-1"><a class="header-anchor" href="#阶段-4-tls-统一">#</a> 阶段 4：TLS 统一</h2><ul><li>使用 bridge TLS 运行时为 WS 添加 TLS 配置。</li><li>向客户端添加固定。</li></ul><h2 id="阶段-5-弃用-bridge" tabindex="-1"><a class="header-anchor" href="#阶段-5-弃用-bridge">#</a> 阶段 5：弃用 bridge</h2><ul><li>将 iOS/Android/mac 节点迁移到 WS。</li><li>保持 bridge 作为后备；稳定后移除。</li></ul><h2 id="阶段-6-设备绑定认证" tabindex="-1"><a class="header-anchor" href="#阶段-6-设备绑定认证">#</a> 阶段 6：设备绑定认证</h2><ul><li>所有非本地连接都需要基于密钥的身份。</li><li>添加撤销 + 轮换 UI。</li></ul><hr><h1 id="安全说明" tabindex="-1"><a class="header-anchor" href="#安全说明">#</a> 安全说明</h1><ul><li>角色/允许列表在 Gateway 网关边界强制执行。</li><li>没有客户端可以在没有 operator 作用域的情况下获得&quot;完整&quot;API。</li><li><em>所有</em>连接都需要配对。</li><li>TLS + 固定减少移动设备的 MITM 风险。</li><li>SSH 静默批准是便利措施；仍然记录 + 可撤销。</li><li>设备发现永远不是信任锚。</li><li>能力声明通过按平台/类型的服务器允许列表验证。</li></ul><h1 id="流式传输-大型负载-节点媒体" tabindex="-1"><a class="header-anchor" href="#流式传输-大型负载-节点媒体">#</a> 流式传输 + 大型负载（节点媒体）</h1><p>WS 控制平面对于小消息没问题，但节点还做：</p><ul><li>相机剪辑</li><li>屏幕录制</li><li>音频流</li></ul><p>选项：</p><ol><li>WS 二进制帧 + 分块 + 背压规则。</li><li>单独的流式端点（仍然是 TLS + 认证）。</li><li>对于媒体密集型命令保持 bridge 更长时间，最后迁移。</li></ol><p>在实现前选择一个以避免漂移。</p><h1 id="能力-命令策略" tabindex="-1"><a class="header-anchor" href="#能力-命令策略">#</a> 能力 + 命令策略</h1><ul><li>节点报告的 caps/commands 被视为<strong>声明</strong>。</li><li>Gateway 网关强制执行每平台允许列表。</li><li>任何新命令都需要操作者批准或显式允许列表更改。</li><li>用时间戳审计更改。</li></ul><h1 id="审计-速率限制" tabindex="-1"><a class="header-anchor" href="#审计-速率限制">#</a> 审计 + 速率限制</h1><ul><li>记录：配对请求、批准/拒绝、令牌颁发/轮换/撤销。</li><li>速率限制配对垃圾和审批提示。</li></ul><h1 id="协议卫生" tabindex="-1"><a class="header-anchor" href="#协议卫生">#</a> 协议卫生</h1><ul><li>显式协议版本 + 错误代码。</li><li>重连规则 + 心跳策略。</li><li>在线状态 TTL 和最后在线语义。</li></ul><hr><h1 id="开放问题" tabindex="-1"><a class="header-anchor" href="#开放问题">#</a> 开放问题</h1><ol><li><p>同时运行两个角色的单个设备：令牌模型</p><ul><li>建议每个角色单独的令牌（node vs operator）。</li><li>相同的 deviceId；不同的作用域；更清晰的撤销。</li></ul></li><li><p>操作者作用域粒度</p><ul><li>read/write/admin + approvals + pairing（最小可行）。</li><li>以后考虑每功能作用域。</li></ul></li><li><p>令牌轮换 + 撤销 UX</p><ul><li>角色更改时自动轮换。</li><li>按 deviceId + 角色撤销的 UI。</li></ul></li><li><p>设备发现</p><ul><li>扩展当前 Bonjour TXT 以包含 WS TLS 指纹 + 角色提示。</li><li>仅作为定位器提示处理。</li></ul></li><li><p>跨网络审批</p><ul><li>广播到所有操作者客户端；活跃的 UI 显示模态框。</li><li>先响应者获胜；Gateway 网关强制原子性。</li></ul></li></ol><hr><h1 id="总结-tl-dr" tabindex="-1"><a class="header-anchor" href="#总结-tl-dr">#</a> 总结（TL;DR）</h1><ul><li>当前：WS 控制平面 + Bridge 节点传输。</li><li>痛点：审批 + 重复 + 两个栈。</li><li>提议：一个带有显式角色 + 作用域的 WS 协议，统一配对 + TLS 固定，Gateway 网关托管的审批，稳定设备 ID + 可爱别名。</li><li>结果：更简单的 UX，更强的安全性，更少的重复，更好的移动路由。</li></ul>',133)])])}const b=l(r,[["render",c]]);export{p as __pageData,b as default};
